item.description:
交换两个变量的数值 var a = 10, b = 20; a = [b, b = a][0]; console.log(a); // 20 console.log(b); // 10 使用 keys 迭代 获取对象的键名，并组成一个数组。
// 迭代对象 var o = {a: &#39;A&#39;, b: &#39;B&#39;, c: &#39;C&#39;}; console.log(Object.keys(o)); // [&#34;a&#34;, &#34;b&#34;, &#34;c&#34;] // 迭代数组 var a = [&#39;A&#39;, &#39;B&#39;, &#39;C&#39;]; console.log(Object.keys(a)); // [&#34;0&#34;, &#34;1&#34;, &#34;2&#34;] 使用 getOwnPropertyNames 迭代 getOwnPropertyNames 的作用和 keys 相同，不同在于 keys 仅能迭代本地的可枚举的属性，getOwnPropertyNames 可以迭代所有的本地属性。
// 迭代对象 var o = {a: &#39;A&#39;, b: &#39;B&#39;, c: &#39;C&#39;}; console.
